<!--
* @Author: zhangbo
* @Descripttion: 立图自定义标注组件-父组件（控制+数据）
* @Date: 2026-01-27
* @Update: 2026-01-28 开启鼠标滚轮缩放开关，修复联动逻辑
-->
<template>
  <div class="annotation-page">
    <!-- 控制面板：操作类型+缩放设置+功能按钮 -->
    <div class="control-panel">
      <div class="type-group">
        <label>操作类型：</label>
        <button
            v-for="type in operationTypes"
            :key="type.value"
            :class="{ active: currentType === type.value }"
            @click="currentType = type.value"
            :disabled="!enableScale && type.value === 'pan'"
        >
          {{ type.label }}
        </button>
      </div>
      <div class="text-group" v-if="!isPanMode">
        <label>标注文字：</label>
        <input
            v-model="annotationText"
            placeholder="输入标注显示文字"
            maxlength="20"
        >
      </div>
      <div class="scale-group">
        <label>缩放设置：</label>
        <label class="scale-switch">
          <input
              type="checkbox"
              v-model="enableScale"
              class="switch-input"
          >
          <span class="switch-slider"></span>
          启用缩放
        </label>
        <label class="scale-switch" style="margin-left: 15px;">
          <input
              type="checkbox"
              v-model="enableMouseCenterScale"
              class="switch-input"
              :disabled="!enableScale"
          >
          <span class="switch-slider"></span>
          启用鼠标缩放
        </label>
        <button
            @click="setScale(1)"
            :disabled="!enableScale || currentScale === 1"
        >
          重置1:1
        </button>
        <button
            @click="setScale(currentScale - scaleStep)"
            :disabled="!enableScale || currentScale <= minScale"
        >
          缩小
        </button>
        <button
            @click="setScale(currentScale + scaleStep)"
            :disabled="!enableScale || currentScale >= maxScale"
        >
          放大
        </button>
        <span class="scale-tip" v-if="enableScale">
          当前：{{ (currentScale * 100).toFixed(0) }}%
        </span>
        <span class="scale-tip" v-else style="color: #999;">
          缩放已关闭
        </span>
      </div>
      <div class="btn-group">
        <button @click="clearAllAnnotations" :disabled="isPanMode">清空标注</button>
        <button @click="getAllAnnotationData" :disabled="isPanMode">获取标注数据</button>
        <button @click="loadSavedAnnotations" :disabled="isPanMode">加载保存的标注</button>
      </div>
    </div>

    <!-- 标注子组件：核心绘制+交互 -->
    <LTLabel
        ref="ltLabelRef"
        :imageUrl="imageUrl"
        :currentType="currentType"
        :annotationText="annotationText"
        :initAnnotations="savedAnnotations"
        :scaleStep="scaleStep"
        :minScale="minScale"
        :maxScale="maxScale"
        :enableMouseCenterScale="enableMouseCenterScale"
        :enableScale="enableScale"
        :isPanMode="isPanMode"
        @annotationComplete="handleAnnotationComplete"
        @initAnnotationsRendered="handleInitRendered"
        @scaleChange="handleScaleChange"
    />

    <!-- 标注列表：Pan模式下隐藏 -->
    <div class="annotation-list" v-if="!isPanMode">
      <h3>标注列表（共{{annotationList.length}}个）</h3>
      <div v-if="annotationList.length === 0" class="empty-tip">暂无标注数据</div>
      <div v-else class="annotation-item" v-for="(anno, index) in annotationList" :key="anno.id">
        <div class="item-header">
          <span>序号：{{index + 1}}</span>
          <span>类型：{{getTypeName(anno.type)}}</span>
          <span>文字：{{anno.annotationText}}</span>
          <button class="delete-btn" @click="deleteAnnotation(anno.id)">删除</button>
        </div>
        <div class="item-detail">
          <template v-if="anno.type === 'rect'">
            原图坐标：x={{anno.x.toFixed(2)}}, y={{anno.y.toFixed(2)}}
            | 尺寸：宽={{anno.width.toFixed(2)}}, 高={{anno.height.toFixed(2)}}
          </template>
          <template v-if="anno.type === 'line'">
            起点：({{anno.x.toFixed(2)}}, {{anno.y.toFixed(2)}})
            | 终点：({{(anno.x + anno.width).toFixed(2)}}, {{(anno.y + anno.height).toFixed(2)}})
          </template>
          <template v-if="anno.type === 'polygon'">
            顶点数：{{anno.points.length}}个
            | 第一个顶点：({{anno.points[0].x.toFixed(2)}}, {{anno.points[0].y.toFixed(2)}})
          </template>
          <template v-if="anno.type === 'point'">
            原图坐标：x={{anno.x.toFixed(2)}}, y={{anno.y.toFixed(2)}}
          </template>
        </div>
      </div>
    </div>
  </div>
</template>

<script>

export default {
  name: 'AnnotationParent',
  data() {
    return {
      // 图片地址（替换为你的图片路径）
      imageUrl: require('./image/NF22A094CF0S_8_1769523011.jpg'),
      // 操作类型：含标注类型+Pan平移
      operationTypes: [
        { label: '矩形', value: 'rect' },
        { label: '直线', value: 'line' },
        { label: '多边形', value: 'polygon' },
        { label: '点', value: 'point' },
        { label: '平移', value: 'pan' }
      ],
      currentType: 'rect',
      annotationText: '缺陷区域',
      // 模拟保存的标注数据（可替换为后端返回数据）
      savedAnnotations: [
        {
          annotationText:"缺陷区域",
          height:249.36877076411957,
          type:"rect",
          width:181.19601328903653,
          x:340.16611295681076,
          y:481.6943521594685
        },
        {
          "id": 1769069036789.1702,
          "type": "rect",
          "annotationText": "缺陷区域",
          "x": 32.91181669060682,
          "y": 42.92845257903494,
          "width": 73.87687188019966,
          "height": 76.87188019966722
        },
        {
          "id": 1769069043810.3809,
          "type": "line",
          "annotationText": "缺陷区域",
          "x": 38.90183332954193,
          "y": 373.37770382695504,
          "width": 182.69550748752079,
          "height": 5.990016638935117
        },
        {
          "id": 1769069050769.626,
          "type": "polygon",
          "annotationText": "缺陷区域",
          "points": [
            {"x": 419.2678899019213, "y": 83.86023294509151},
            {"x": 404.2928483045835, "y": 75.87354409317804},
            {"x": 394.3094872396917, "y": 84.8585690515807},
            {"x": 392.3128150267133, "y": 103.8269550748752},
            {"x": 394.3094872396917, "y": 119.80033277870216},
            {"x": 402.29617609160516, "y": 128.78535773710482},
            {"x": 430.24958707330234, "y": 127.78702163061564},
            {"x": 432.2462592862807, "y": 99.83361064891847},
            {"x": 430.24958707330234, "y": 77.87021630615641},
            {"x": 430.24958707330234, "y": 77.87021630615641}
          ]
        },
        {
          "id": 1769069052591.5781,
          "type": "point",
          "annotationText": "缺陷区域",
          "x": 234.5757102014221,
          "y": 178.70216306156405
        }
      ],
      annotationList: [],
      // 缩放配置（统一控制）
      currentScale: 1,
      scaleStep: 0.1,
      minScale: 0.5,
      maxScale: 5,
      enableScale: true, // 默认开启缩放
      enableMouseCenterScale: true // 默认开启鼠标滚轮缩放
    }
  },
  computed: {
    // 判断是否为Pan平移模式
    isPanMode() {
      return this.currentType === 'pan';
    }
  },
  methods: {
    // 标注完成回调
    handleAnnotationComplete(annotation) {
      this.annotationList.push(annotation)
    },
    // 初始标注回显完成回调
    handleInitRendered(annotations) {
      this.annotationList = annotations
      console.log('标注回显完成：', annotations)
    },
    // 清空所有标注
    clearAllAnnotations() {
      this.$refs.ltLabelRef.clearAnnotations()
      this.annotationList = []
    },
    // 删除单个标注
    deleteAnnotation(id) {
      this.$refs.ltLabelRef.deleteAnnotationById(id)
      this.annotationList = this.annotationList.filter(anno => anno.id !== id)
    },
    // 获取所有标注原始数据
    getAllAnnotationData() {
      const allData = this.$refs.ltLabelRef.getAllAnnotations()
      console.log('原始格式标注数据：', allData)
      alert(`已获取${allData.length}个标注数据，详情请查看控制台！`)
    },
    // 加载保存的标注数据
    loadSavedAnnotations() {
      this.$refs.ltLabelRef.renderInitAnnotations(this.savedAnnotations)
    },
    // 获取标注类型名称
    getTypeName(type) {
      const item = this.operationTypes.find(item => item.value === type)
      return item ? item.label : type
    },
    // 监听缩放比例变化（子组件同步）
    handleScaleChange(scale) {
      this.currentScale = scale
      console.log('缩放比例变化：', scale)
    },
    // 手动设置缩放比例（核心：父组件控制子组件缩放）
    setScale(targetScale) {
      if (!this.enableScale) return;
      // 限制缩放边界
      const newScale = Math.max(this.minScale, Math.min(this.maxScale, targetScale));
      this.$refs.ltLabelRef.setScale(newScale);
      this.currentScale = newScale;
    }
  }
}
</script>

<style scoped>
.annotation-page {
  width: 1200px;
  margin: 20px auto;
  font-family: "Microsoft Yahei", sans-serif;
}

.control-panel {
  display: flex;
  align-items: center;
  gap: 20px;
  padding: 10px 15px;
  background-color: #f5f5f5;
  border-radius: 6px;
  margin-bottom: 15px;
  flex-wrap: wrap;
}

.control-panel .type-group label,
.control-panel .text-group label,
.control-panel .scale-group label {
  margin-right: 8px;
  font-weight: 600;
  color: #333;
}

.control-panel button {
  padding: 6px 12px;
  border: none;
  border-radius: 4px;
  background-color: #0099ff;
  color: white;
  cursor: pointer;
  transition: background-color 0.2s;
}

.control-panel button.active {
  background-color: #0066cc;
}

.control-panel button:hover {
  background-color: #0088ee;
}

.control-panel button:disabled {
  background-color: #cccccc;
  cursor: not-allowed;
}

/* 缩放开关样式 */
.scale-switch {
  display: flex;
  align-items: center;
  gap: 8px;
  cursor: pointer;
  margin-right: 10px;
}
.switch-input {
  display: none;
}
.switch-slider {
  width: 36px;
  height: 20px;
  background-color: #ccc;
  border-radius: 10px;
  position: relative;
  transition: background-color 0.2s;
}
.switch-slider::after {
  content: '';
  position: absolute;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background-color: white;
  top: 2px;
  left: 2px;
  transition: transform 0.2s;
}
.switch-input:checked + .switch-slider {
  background-color: #0099ff;
}
.switch-input:checked + .switch-slider::after {
  transform: translateX(16px);
}

/* 缩放控制区样式 */
.control-panel .scale-group {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: nowrap;
}
.control-panel .scale-group button {
  padding: 6px 10px;
  font-size: 14px;
}
.scale-tip {
  margin-left: 5px;
  color: #666;
  font-size: 14px;
  white-space: nowrap;
}

.control-panel .text-group input {
  padding: 6px 8px;
  border: 1px solid #ddd;
  border-radius: 4px;
  width: 180px;
}

/* 标注列表样式 */
.annotation-list {
  margin-top: 20px;
  padding: 15px;
  border: 1px solid #eee;
  border-radius: 6px;
}
.annotation-list h3 {
  margin: 0 0 15px 0;
  color: #333;
  font-size: 16px;
}
.annotation-list .empty-tip {
  text-align: center;
  color: #999;
  padding: 20px 0;
}
.annotation-list .annotation-item {
  padding: 10px;
  border-bottom: 1px dashed #eee;
  margin-bottom: 10px;
}
.annotation-list .annotation-item:last-child {
  border-bottom: none;
  margin-bottom: 0;
}
.annotation-list .item-header {
  display: flex;
  align-items: center;
  gap: 15px;
  margin-bottom: 8px;
  flex-wrap: wrap;
}
.annotation-list .item-header span {
  color: #666;
}
.annotation-list .delete-btn {
  margin-left: auto;
  padding: 4px 8px;
  background-color: #ff4444;
  color: white;
  border: none;
  border-radius: 3px;
  cursor: pointer;
  font-size: 12px;
}
.annotation-list .item-detail {
  color: #888;
  font-size: 14px;
  line-height: 1.5;
}

/* 响应式适配 */
@media (max-width: 1200px) {
  .annotation-page {
    width: 95%;
  }
  .control-panel .scale-group {
    flex-wrap: wrap;
    margin-top: 10px;
    width: 100%;
  }
}
</style>